// Manual type aliases for types with custom Serialize impls

/**
 * A floating object: common metadata + type-specific data.
 * Rust `FloatingObject` uses a custom Serialize impl that merges
 * `FloatingObjectCommon` and `FloatingObjectData` into a single flat JSON object.
 */
export type FloatingObject = FloatingObjectCommon & FloatingObjectData;
